#!/bin/bash
set -e
DIR="/home/automystics-scada/htdocs/scada.automystics.tech"
cd "$DIR" || { echo "ERROR: deploy dir not found"; exit 1; }
echo "=== [1/7] Writing updated source files ==="
python3 - << 'PYEOF'
import base64, pathlib
files = {
  'artifacts/solar-scada/src/pages/platform-admin-login.tsx': '',
  'artifacts/solar-scada/src/pages/login.tsx': '',
  'artifacts/api-server/src/routes/auth-otp.ts': '',
  'artifacts/api-server/src/routes/platform-admin-auth.ts': '',
  'artifacts/api-server/src/routes/index.ts': '',
  'artifacts/api-server/src/lib/mailer.ts': '',
}
for p, b in files.items():
    pathlib.Path(p).parent.mkdir(parents=True, exist_ok=True)
    pathlib.Path(p).write_bytes(base64.b64decode(b))
    print(f"  wrote {p}")
PYEOF

echo "=== [2/7] PostgreSQL setup ==="
sudo -u postgres psql << 'SQL' 2>/dev/null || true
DO $$ BEGIN
  IF NOT EXISTS (SELECT FROM pg_roles WHERE rolname = 'scada') THEN
    CREATE USER scada WITH PASSWORD 'scada';
  END IF;
END $$;
SQL
sudo -u postgres psql -c "CREATE DATABASE solar_scada OWNER scada;" 2>/dev/null || true
sudo -u postgres psql -d solar_scada -c "GRANT ALL ON SCHEMA public TO scada;" 2>/dev/null || true

echo "=== [3/7] Installing dependencies ==="
pnpm --filter @workspace/api-server add nodemailer --silent 2>/dev/null || true

echo "=== [4/7] DB migrations ==="
pnpm --filter @workspace/db run db:push

echo "=== [5/7] Building API ==="
pnpm --filter @workspace/api-server run build

echo "=== [6/7] Building frontend ==="
PORT=3000 BASE_PATH=/ pnpm --filter @workspace/solar-scada run build

echo "=== [7/7] Restarting services ==="
systemctl daemon-reload
systemctl restart solar-scada-api
sleep 5
systemctl restart solar-scada-proxy 2>/dev/null || true
sleep 2

echo ""
echo "=== Health checks ==="
API=$(curl -s -o /dev/null -w "%{http_code}" http://127.0.0.1:8080/api/healthz)
echo "  API: HTTP $API"
ROUTE=$(curl -s -X POST http://127.0.0.1:8080/api/platform-admin/login/email -H "Content-Type: application/json" -d '{"email":"automystics.com@gmail.com"}')
echo "  Platform-admin route: $ROUTE"
echo ""
echo "✅ Deploy complete!"
echo "   App:   https://scada.automystics.tech"
echo "   Admin: https://scada.automystics.tech/platform-admin"